/// <summary>
///  Freezes the form fields by updating the design when the data source is activated.
/// </summary>
[ExtensionOf(formDataSourcestr(EcoResProductDimensionGroup,ProductDimGroupFieldSetupProductDim))]
internal final class ETGEcoResProductDimensionGroupsFormDSDMS_Extension
