}

Method.Source:
/// <summary>
 ///  Freezes the form fields by updating the design when the data source is activated.
/// </summary>
/// <returns></returns> 
 public int active()
 {
     int ret;

     EcoResProductDimensionGroupFldSetup     ecoResProductDimensionGroupFldSetup;

     ret = next active();

     ETGDMSIntegrationFormDesignHelper::updateDesignDMS(this);

     ecoResProductDimensionGroupFldSetup = this.cursor();

    if(ETGACFParameters::find().EnableDMSIntegration ==NoYes::Yes)
    {
         FormRun formRun = this.formRun();

         FormCheckBoxControl IsActive                 = formRun.design().controlName("FieldSetupGrid_IsActive") as FormCheckBoxControl;
         FormCheckBoxControl PurchPriceSearchEnabled  = formRun.design().controlName("FieldSetupGrid_IsPurchPriceSearchEnabled") as FormCheckBoxControl;
         FormCheckBoxControl SalesPriceSearchEnabled  = formRun.design().controlName("FieldSetupGrid_IsSalesPriceSearchEnabled") as FormCheckBoxControl;

         if ( IsActive.checked())
         {
             //PurchPriceSearchEnabled.enabled(true);
             //SalesPriceSearchEnabled.enabled(true);
             PurchPriceSearchEnabled.allowEdit(true);
             SalesPriceSearchEnabled.allowEdit(true);

         }
         else
         {
             ecoResProductDimensionGroupFldSetup.IsPurchPriceSearchEnabled = NoYes::No;
             ecoResProductDimensionGroupFldSetup.IsSalesPriceSearchEnabled = NoYes::No;
             PurchPriceSearchEnabled.allowEdit(false);
             SalesPriceSearchEnabled.allowEdit(false);
            // PurchPriceSearchEnabled.enabled(false);
             //SalesPriceSearchEnabled.enabled(false);
             ecoResProductDimensionGroupFldSetup.update();
             this.refresh();

         }
    }
     return ret;
 }
